const Q_ECONOMICS_2006=[{"id": "objective>Economics>2006>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the marginal propensity to consume is 0.6 and consumption expenditure change by ₦10 million, the equilibrium level of income will change by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦4.0 million </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦25.0 million</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦2.5 million </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦15.0 million</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The marginal propensity to consume (MPC) is the increase in consumer spending due to an increase in income. If the MPC is 0.6 and consumption expenditure changes by ₦10 million, the equilibrium level of income will change by ₦25 million. This is because the change in income is equal to the change in consumption divided by (1-MPC). So, ₦10 million / (1-0.6) = ₦25 million.</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : THE CONCEPT OF MULTIPLIER"}, {"id": "objective>Economics>2006>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The price index is calculated as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">(base year price)</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">(current price)</span> x 100</div>", "<div style=\"font-family:Cambria;font-size:17px;\">(current price)/(base year price)x100</div>", "<div style=\"font-family:Cambria;font-size:17px;\">(weighted price)/(current price)x100</div>", "<div style=\"font-family:Cambria;font-size:17px;\">(current price)/(weighted price) x100</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Price index is given as <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">Pc</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">Pb</span> x 100 where Pc is the current year price and Pb is the base year price.</div>", "topic": "INFLATION & DEFLATION : INTRODUCTION"}, {"id": "objective>Economics>2006>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Personal income tax as a source of government revenue is increased when the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tax rate is raised</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tax system is proportional</div>", "<div style=\"font-family:Cambria;font-size:17px;\">retirement age is reduced</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tax base is contracted</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The funds collected from the taxes serve as a country's source of income and are directed to financing various projects for the benefit of its citizens. The maximum corporate tax rate equal to 35%. Personal income tax is a direct tax paid by individuals to the government on their personal income coming from monthly salaries and wages.</div>", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX"}, {"id": "objective>Economics>2006>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In computing national income, transfers payment are excluded because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">they are received only by the poor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the figures reduce the size of national income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it is difficult to get the exact figures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">they are not payments for productive activities</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">payments  known as 'transfer payments' are to be excluded when calculating national income. These are excluded from national income because such incomes do not represent payment for contributing to the production of goods and services.</div>", "topic": "NATIONAL INCOME : CONCEPT"}, {"id": "objective>Economics>2006>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major role of NDIC is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">insure bank deposits</div>", "<div style=\"font-family:Cambria;font-size:17px;\">regulate the activities of insurance companies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensure adequate capitalization of insurance companies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">accept customers' deposits</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The NDIC (Nigeria Deposit Insurance Corporation) is an independent agency of the Federal Republic of Nigeria. This agency exists to insure depositors and guarantee the settlement of insured funds should a financial institution be unable to repay their deposits which in turn will stabilize the financial system.</div>", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC"}, {"id": "objective>Economics>2006>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the federal government guarantees a loan for a state government, such a loan constitutes</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a public debt </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a transferred debt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a private debt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an inter-governmental debt</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When the federal government guarantees a loan for a state government, it is considered an inter-governmental debt. This is because the debt is between two levels of government, the federal and the state. A public debt is a debt owed by a central government. A transferred debt would imply that the debt has been moved from one entity to another, which is not the case here. A private debt is a debt owed by private individuals or corporations, not governments.</div>", "topic": "PUBLIC FINANCE : BUDGET"}, {"id": "objective>Economics>2006>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One way of controlling deflation is by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">contractionary monetary policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreasing wages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deficit financing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rigid fiscal policy</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Deflation can be controlled through currency( credit ) expansion, low bank rate, low reserve ratio, consumer credit, increase in  tax rate, public debt payment, production control etc.</div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>2006>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the Central Bank of Nigeria reduces the bank rate this will cause</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">money supply to increase</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commercial banks to reduce lending</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commercial banks to merge</div>", "<div style=\"font-family:Cambria;font-size:17px;\">money supply to reduce</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When bank rate is reduced it will encourage commercial banks to approach CBN for money thereby increasing money supply.increase in bank rate is an expansionary monetary policy.</div>", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK"}, {"id": "objective>Economics>2006>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main source of government revenue in Nigeria is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">import duties </div>", "<div style=\"font-family:Cambria;font-size:17px;\">rents and royalties</div>", "<div style=\"font-family:Cambria;font-size:17px;\">company income tax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital gains tax</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, the main source of government revenue is from the oil and gas industry, which includes rents and royalties from oil production and exports. While other sources such as import duties, company income tax and capital gains tax contribute to te government's revenue, rents and royalties from natural resources are most significant.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : INTRODUCTION"}, {"id": "objective>Economics>2006>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Revenue Mobilization, Allocation and Fiscal Commission in Nigeria has the primary responsibility for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">maintaining the fiscal supremacy of the central government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">evolving an acceptable wage for public servant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">evolving an acceptable revenue-sharing formula</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensuring equity in the sharing of fiscal responsibilities</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Revenue Mobilization Allocation and Fiscal Commission is a corporate body that occupies a very strategic position in the fiscal administration of the Nigerian government. RMAFC is the regulatory body in charge of the revenue allocation in Nigeria. Revenue sharing formula is one of the major roles of revenue mobilization allocation and fiscal commission in Nigeria.</div>", "topic": "PUBLIC FINANCE : FISCAL POLICY"}, {"id": "objective>Economics>2006>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The burden of a government tax on a commodity whose demand is inelastic will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">be borne only by the government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fall more heavily on consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">be shared equally between consumers and producers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fall more heavily on producers.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When elasticity of demand for a commodity is inelastic the burden is borne by the consumer since it is easier for the producer to shift it on them.</div>", "topic": "PUBLIC FINANCE : ELASTICITY OF TAX"}, {"id": "objective>Economics>2006>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An important determinant of price elasticity of demand is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the state of technology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the prices of other commodities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the ease of substitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government policy</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The existence of close substitute is one of the major determinants of elasticity of demand. The change in the price of a commodity affects the demand for its substitute. the rate of sustitute is a mojor determinant of elasticity of supply. Of all the factors determining price elasticity of demand the availability of the number and kinds of substitutes for a commodity is the most important factor. If for a commodity close substitutes are available, its demand tends to be elastic. <br/> </div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2006>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The range of the data 14, 13, 15, 18, 20, 35 and 13 is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">22 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">13 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">18</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The range of a set of data is the difference between the highest and lowest values in the set. In this case, the highest value is 35 and the lowest value is 13. Therefore, the range is 35 - 13 = 22.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF DISPERSION"}, {"id": "objective>Economics>2006>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the marginal utility of good X exceeds that of good Y, this implies that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a rational consumer will buy less of X</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consuming more of X will increase total utility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Y is an inferior good</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X will be cheaper than Y.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Assume a consumer is spending all her income on two goods: X and Y. At the current consumption combination of the two goods, of the marginal utility per dollar spent on the last unit of good X exceeds that of the marginal utility spent on the last unit of good y, what should the consumer do to maximize utility</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : MARGINAL RATE OF SUBSTITUTION (MRS)"}, {"id": "objective>Economics>2006>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A commodity will be demanded only if</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">consumers' income increases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it has no close substitutes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the price is low government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it has utility</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A commodity will be demanded only if it has utility. Utility refers to the satisfaction or benefit that a consumer receives when they consume a good or service. Even if a commodity is cheap, has no close substitutes, or consumers' income increases, it will not be demanded if it does not provide any satisfaction or benefit to the consumer.</div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2006>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Derived demand is normally used with reference to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">superior goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inferior goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the cost of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the factors of production</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Demand for factors of production is derived demand because factors are demanded for service they will render in production.</div>", "topic": "THEORY OF PRODUCTION (1) : FACTORS OF PRODUCTION"}, {"id": "objective>Economics>2006>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A straight line indifference curve indicates that the two products are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">normal goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inferior goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">perfect substitutes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">close substitutes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When indifference curve is a straight line that mean the two goods are not necessarily combined. Since there is existence of corner solution which implies that on the Y axis Zero amount of X will be demanded and vice versa.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : INDIFFERENCE CURVE"}, {"id": "objective>Economics>2006>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given that demand and price remain unchanged, an outward shift of the supply curve will lead to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hoarding </div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess demand </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a black market</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An outward shift of the supply curve means that at the same price level, more quantity is supplied. If demand remains unchanged, this will lead to excess supply. Excess supply occurs when the quantity of a good supplied is more than the quantity demanded at the current market price.</div>", "topic": "THE THEORY OF SUPPLY : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2006>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><p style=\"padding: 3px;\">Use the diagram below to answer the question that follows</p>  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> A movement from K to M will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase the price of the commodity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">leave the consumer's utility unchanged</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease the consumer's utility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the consumer's utility.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A movement from a point K to M does not have any effect on the consumer. This is because the total utility are equal at both points</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM"}, {"id": "objective>Economics>2006>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">Use the diagram below to answer the question that follows</p>  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> At point P, the marginal rate of substitution is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">greater than one </div>", "<div style=\"font-family:Cambria;font-size:17px;\">zero</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">less than one</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The MRS, along the indifference curve is equal to 1, because the lines are parallel, with the slopes forming 45<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> angle with each axis. MRS is defined as  a fraction because the slope is different when considering different substitutes of goods. MRS will be constant for perfect substitutes.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : MARGINAL RATE OF SUBSTITUTION (MRS)"}, {"id": "objective>Economics>2006>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A distribution is said to be positively skewed if it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">has a long tail to the left</div>", "<div style=\"font-family:Cambria;font-size:17px;\">has a long tail to the right</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is bimodal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is bell-shaped</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If a distribution is asymmetric it is either positively skewed or negatively skewed. A distribution is said to be positively skewed if the scores tend to cluster toward the lower end of the scale (that is, the smaller numbers) with increasingly fewer scores at the upper end of the scale (that is, the larger numbers).</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF DISPERSION"}, {"id": "objective>Economics>2006>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A decision on input combination solves the economic problem of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">how to produce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">for whom to produce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">when to produce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">what to produce</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The problem of how to produce is a technical issue and has to do with how factors/input can be combined in order to produce a good.</div>", "topic": "THEORY OF PRODUCTION (1) : FACTORS OF PRODUCTION"}, {"id": "objective>Economics>2006>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Choice involves opportunity cost because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">goods give different utilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">available resources are inadequate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there are many goods to select from</div>", "<div style=\"font-family:Cambria;font-size:17px;\">not all goods have the same price.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Choice is made out of alternative goods due to limited/scarce resources otherwise, consumer would have demanded every good he want if he had unlimited resources.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONCEPT"}, {"id": "objective>Economics>2006>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The law of demand can be expressed as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">d</span> = f(P) </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">d</span> =f<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">(1)</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">(P)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">P = f<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">(1)</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">d</span></span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">P = f(Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">d</span>)</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The law of demand relates quantity demand to price. In mathematical form Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">d</span> =f<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">(1)</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">(P)  </span>i.e quantity demand depends on price which express the inverse relationship between demand and price.</div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2006>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria's exports usually comprise</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Primary goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intermediate goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumer goods</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From statistics, the non-oil products Nigeria exports most are cocoa, palm oil, cassava, rubber, wool, cotton, wood logs (Iroko and Mahogany) groundnut oil, cashew, garlic, etc .The exports of Nigeria comprises mainly primarily product from agriculture and mining.</div>", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE"}, {"id": "objective>Economics>2006>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A characteristic common to partnership and sole proprietorship is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">limited liability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">accessibility to loans</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transferability of shares</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unlimited liability.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Both the partnership and sole proprietorship has unlimited liability i.e can sue and be sued in the court of law.</div>", "topic": "BUSINESS ORGANISATION : PARTNERSHIP"}, {"id": "objective>Economics>2006>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Economic growth can be accelerated through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">excess current consumption</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess consumption</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increased current consumption</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increased current investment</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Economic growth can be accelerated through increased current investment. Investment in this context refers to the addition to the stock of capital goods in an economy, such as factories, machinery, and equipment, which can increase the productive capacity of the economy. Excess or increased current consumption would not lead to economic growth as it does not contribute to the productive capacity of the economy.</div>", "topic": "ECONOMIC DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>2006>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The exchange rate determined by market forces is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pegged exchange rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">floating exchange rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixed exchange rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dual exchange rate</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The exchange rate determined by market forces is known as a floating exchange rate. This is because in a floating exchange rate system, the market determines the value of the currency. This is in contrast to a fixed exchange rate, where the government sets the rate, or a pegged exchange rate, where the currency's value is fixed to another currency's value. A dual exchange rate is a system where a country maintains a fixed exchange rate for some transactions and a floating rate for others, which is not the case here.</div>", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE"}, {"id": "objective>Economics>2006>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An association formed by a group of individuals solely for the marketing of their product is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">credit and thrift society</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumer cooperative society</div>", "<div style=\"font-family:Cambria;font-size:17px;\">producer cooperative society</div>", "<div style=\"font-family:Cambria;font-size:17px;\">voluntary organization.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When group of people come together to market their products, the association formed is producer cooperative society.</div>", "topic": "BUSINESS ORGANISATION : CO-OPERATIVE SOCIETIES"}, {"id": "objective>Economics>2006>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Import substitution policy is used to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">protect local industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">check government expenditure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">correct the balance of payments problem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encourage increased volume of trade</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Import substitution policy is a trade policy which advocates replacing foreign imports with domestic production. It is based on the premise that a country should attempt to reduce its foreign dependency through the local production of industrialized products. The policy advocates the protection of local industries so they may become self-sustainable.</div>", "topic": "INTERNATIONAL TRADE : ECONOMIC INTEGRATION IN AFRICA"}, {"id": "objective>Economics>2006>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The organization whose aim is to solve the trade problems of less developed nations is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">UNCTAD </div>", "<div style=\"font-family:Cambria;font-size:17px;\">OECD</div>", "<div style=\"font-family:Cambria;font-size:17px;\">UNECA </div>", "<div style=\"font-family:Cambria;font-size:17px;\">WTO</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">UNCTAD was established in 1964 with the aim of assisting the developing countries to solve their balance of payment problem.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC"}, {"id": "objective>Economics>2006>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Mobility of labour is higher when there </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is a monopoly of jobs in one location</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is intense competition for jobs in the same location</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are alternative jobs in the same location</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are no alternative jobs in the same location</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mobility of labour is higher when there are alternative jobs in the same location. This is because workers have more options to choose from and can easily switch from one job to another without having to relocate. This is a basic concept in labor economics, where labor mobility refers to the ability of workers to move and adapt to changing job opportunities.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR"}, {"id": "objective>Economics>2006>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major advantage of industrialization is that it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">leads to self-reliance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">curbs inflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">leads to growth and development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">improves the terms of trade</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Industrialization refers to transformation of economic structure of a country from primary production to production of industrial goods and services for the purpose of attaining economic growth and development.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>2006>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The oil-producing areas in Nigeria are agitating for special compensation owing mainly to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the high level of poverty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the high level of unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">constant flooding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">environmental pollution</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Most of the oil producing areas in Nigeria are exposed to environmental pollution in forms of oil spillage, emission of dangerous gas substance into the air this provoke agitation for compensation.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : ONSHORE & OFFSHORE OF THE OIL SECTOR"}, {"id": "objective>Economics>2006>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If children and the aged dominate the population of a country, this results in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a reduction in the importation of capital goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a fall in the standard of living</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in the national income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an improvement in the standard of living.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Standard of living will fall when the dependency ratio is very high; children and aged constitute dependants.</div>", "topic": "POPULATION : POPULATION STRUCTURE/ DISTRIBUTION"}, {"id": "objective>Economics>2006>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major factor militating against rapid industrialization in Nigeria is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">inadequate skilled manpower</div>", "<div style=\"font-family:Cambria;font-size:17px;\">poor market facilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">poor transport facilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">epileptic power supply</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Epileptic power supply is a major factor militating against industrialization as most companies would have to incur a huge cost in providing and running generator.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>2006>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Minimum wage legislation will result in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reduced income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">greater supply for labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduced labour productivity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">greater demand of labour.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Minimum wage legislation often results in reduced labour productivity. This is because when the minimum wage is set above the equilibrium wage rate, it can lead to a surplus of labour (unemployment) as employers cannot afford to hire as many workers. This can lead to a decrease in overall productivity as there are fewer workers to produce goods and services. Furthermore, those who are employed may also become less productive as they are guaranteed a certain wage regardless of their output.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : DEMAND FOR LABOUR"}, {"id": "objective>Economics>2006>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The term 'oil shock' is used to describe a situation in which</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the demand for oil exceeds its supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oil prices have fallen drastically</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the demand for oil is equal to its supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the supply of oil exceeds its demand.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The term 'oil shock' is used to describe a situation where there is a sudden and drastic change in oil prices due to a decrease in supply. This usually happens when the demand for oil exceeds its supply, leading to a sharp increase in oil prices. This is because when demand exceeds supply, the price of a commodity tends to rise according to the law of supply and demand.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : INTRODUCTION"}, {"id": "objective>Economics>2006>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major problem of conducting a census in Nigeria is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">inadequate skilled personnel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">financial constraint</div>", "<div style=\"font-family:Cambria;font-size:17px;\">urban congestion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lack of political will</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Census is an expensive exercise that requires a huge financial commitment on the part of government. In Nigeria, financial constraints constitute a serious problem of conducting census.</div>", "topic": "POPULATION : INTRODUCTION"}, {"id": "objective>Economics>2006>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The marginal productivity theory applies in a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">unionized labour market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">perfectly competitive market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monopolistic market only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monopolistic market only.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to this theory, under perfect competition, the price of services rendered by a factor of production is equal to its marginal productivity. Marginal product refers to the increase in amount of output by the addition of one unit of factor of production while keeping the other factors constant.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : INTRODUCTION"}, {"id": "objective>Economics>2006>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A rising short-run average cost is a result of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">economies of scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">falling marginal cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diminishing returns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rising fixed costs</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the short-run, if output is reduced, average cost will rise because the fixed costs will work out at a higher figure. </div>", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST"}, {"id": "objective>Economics>2006>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The only factor of production that plays an active role in the production process is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">land </div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">entrepreneur </div>", "<div style=\"font-family:Cambria;font-size:17px;\">labour</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the context of economics, factors of production are the inputs used in the production of goods or services in the attempt to make an economic profit. These factors include land, labor, capital, and entrepreneurship. Among these, labor is the only factor that plays an active role in the production process. Labor refers to the human effort that is used in the creation of goods and services. Labor resources include the work done by the waiter who brings your food at a local restaurant as well as the engineer who designed the restaurant's building.</div>", "topic": "THEORY OF PRODUCTION (1) : FACTORS OF PRODUCTION"}, {"id": "objective>Economics>2006>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The market structure in which there is interdependent of price-output policies is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a pure monopoly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an oligopoly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a pure competition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a monopolistic competition.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In economics, market structures are classified into four main types: perfect competition, monopolistic competition, oligopoly, and monopoly. An oligopoly is a market structure in which a few firms dominate. When a market is shared between a few firms, it is said to be highly concentrated. Although only a few firms dominate, it is possible that many small firms may also operate in the market. In an oligopoly, firms are interdependent because each firm must consider the reactions of its rivals to its actions. So, the price-output policies of all the firms are interdependent.</div>", "topic": "MARKET STRUCTURE : OLIGOPOLY"}, {"id": "objective>Economics>2006>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the short-run cost curve of a firm is U-shaped, the marginal and average costs are equal where the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">average variable cost is minimum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal cost is falling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">average cost is minimum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">average fixed cost is falling.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the short run, the marginal cost (MC) curve intersects the average total cost (ATC) curve at the minimum point of the ATC. This is because when MC is less than ATC, ATC is falling, and when MC is more than ATC, ATC is rising. Therefore, the point where MC equals ATC is the minimum point of the ATC curve, which is why the answer is 'average cost is minimum'.</div>", "topic": "THE CONCEPT OF COST & REVENUE : THE MARGINAL COST & SUPPLY CURVE OF A FIRM"}, {"id": "objective>Economics>2006>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  <br/> The diagram above shows the effect of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">maximum price legislation at P2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">minimum price legislation at P2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess supply over demand at q2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess demand over supply at q3.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Any point below equilibrium price is regarded as maximum price legislation which is fixed by the government. If the price is fixed on the commodity (or labour), there will be excess of demand over supply.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : PRICE LEGISLATION"}, {"id": "objective>Economics>2006>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A perfectly competitive firm is advised to close down when the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">price is below the marginal cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price is equal to the marginal revenue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal revenue is equal to the marginal cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price is below the average variable cost.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A firm will close down if it cannot cover its average variable cost. The moment its price falls below average variable cost, it must close down.</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>2006>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">*!Use the table below to answer the question that follows!  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Number of men </td><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\"> 2 </td><td style=\"border:1px solid black;text-align:center;\">3 </td><td style=\"border:1px solid black;text-align:center;\">4</td><td style=\"border:1px solid black;text-align:center;\"> 5 </td><td style=\"border:1px solid black;text-align:center;\">6</td><td style=\"border:1px solid black;text-align:center;\"> 7</td><td style=\"border:1px solid black;text-align:center;\"> 8 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Total production(Unit)</td><td style=\"border:1px solid black;text-align:center;\">200</td><td style=\"border:1px solid black;text-align:center;\"> 440</td><td style=\"border:1px solid black;text-align:center;\"> 540</td><td style=\"border:1px solid black;text-align:center;\"> 600</td><td style=\"border:1px solid black;text-align:center;\"> 640</td><td style=\"border:1px solid black;text-align:center;\"> 660</td><td style=\"border:1px solid black;text-align:center;\"> 660</td><td style=\"border:1px solid black;text-align:center;\"> 640</td></tr></table></div> <br/>  <br/> What is the average product when 3 men are employed?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">180 units </div>", "<div style=\"font-family:Cambria;font-size:17px;\">100 units</div>", "<div style=\"font-family:Cambria;font-size:17px;\">540 units </div>", "<div style=\"font-family:Cambria;font-size:17px;\">120 units</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">AP</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">TP<hr size=\"1\" />Q</td><td style=\"text-align:center;\"></td></tr><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">AP<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">540<hr size=\"1\" />3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">180</td><td style=\"text-align:center;\">units</td><td style=\"text-align:center;\"></td></tr></table></div>  <br/>  </div>", "topic": "THEORY OF PRODUCTION (2) : CONCEPTS OF PRODUCTION"}, {"id": "objective>Economics>2006>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> *!Use the table below to answer the question that follows!  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Number of men </td><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\"> 2 </td><td style=\"border:1px solid black;text-align:center;\">3 </td><td style=\"border:1px solid black;text-align:center;\">4</td><td style=\"border:1px solid black;text-align:center;\"> 5 </td><td style=\"border:1px solid black;text-align:center;\">6</td><td style=\"border:1px solid black;text-align:center;\"> 7</td><td style=\"border:1px solid black;text-align:center;\"> 8 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Total production(Unit)</td><td style=\"border:1px solid black;text-align:center;\">200</td><td style=\"border:1px solid black;text-align:center;\"> 440</td><td style=\"border:1px solid black;text-align:center;\"> 540</td><td style=\"border:1px solid black;text-align:center;\"> 600</td><td style=\"border:1px solid black;text-align:center;\"> 640</td><td style=\"border:1px solid black;text-align:center;\"> 660</td><td style=\"border:1px solid black;text-align:center;\"> 660</td><td style=\"border:1px solid black;text-align:center;\"> 640</td></tr></table></div> <br/> If the price per unit is ₦2, what is the average revenue when 6 men are employed?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦110 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦120 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦220 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦330</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The average revenue is calculated by multiplying the price per unit by the total production, and then dividing by the number of men.  <br/>  <br/> In this case, when 6 men are employed, the total production is 660 units and the price per unit is ₦2.  <br/>  <br/> Therefore, the average revenue is (660x 2)/6  <br/> = ₦220</div>", "topic": "THE CONCEPT OF COST & REVENUE : THE CONCEPT OF REVENUE"}, {"id": "objective>Economics>2006>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Product differentiation in monopolistic competition implies that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">different product are sold to the same buyer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">different buyers pay different prices for the same product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sellers determine whom to sell their products to</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the same product is available in different forms</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Product differential occurs when products are identical but differentiated by trade man`s packaging. The same product is available in different forms.</div>", "topic": "MARKET STRUCTURE : MONOPOLISTIC COMPETITION"}, {"id": "objective>Economics>2006>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A constraint on the expansion of a firm is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rate of advertisement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">size of the market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">level of the production income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tastes of the consumers</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Size of the market is usually considered before a firm can embark on expansion. Where market size is large, a firm can engage on a large scale production.</div>", "topic": "BUSINESS ORGANISATION : INTRODUCTION"}];
